// lib/questions.js
//
// This defines the RULE-BASED branching layer: deterministic, free, instant.
// Each section has a list of questions. Some questions only appear
// if a condition on prior answers is met (see `showIf`).
//
// The AI-DRIVEN layer (dynamic follow-up questions generated by Claude)
// is handled separately in app/api/next-question/route.js and is used
// on top of this — typically once per section, after the base questions
// in that section are answered.

