// Returns only the questions that should currently be visible for a section,
// given the answers collected so far.
export function visibleQuestions(sectionId, answers) {
  const section = SECTIONS.find((s) => s.id === sectionId);
  if (!section) return [];
  return section.questions.filter((q) => (q.showIf ? q.showIf(answers) : true));
}
